import React, { useState, useEffect, useRef, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

const tanhFn = (x) => {
  const ep = Math.exp(x);
  const en = Math.exp(-x);
  return (ep - en) / (ep + en);
};
const dyt = (x, a, g, b) => g * tanhFn(a * x) + b;

const sampleColors = ['#38bdf8', '#fbbf24', '#a3e635', '#f472b6', '#fb923c'];

export default function App() {
  const [alpha, setAlpha] = useState(0.5);
  const [gamma, setGamma] = useState(1.0);
  const [beta, setBeta] = useState(0.0);
  const [hoverX, setHoverX] = useState(null);
  const [playing, setPlaying] = useState(false);
  const svgRef = useRef(null);
  const animRef = useRef(null);
  const startRef = useRef(null);

  useEffect(() => {
    if (playing) {
      startRef.current = null;
      const duration = 5000;
      const animate = (ts) => {
        if (!startRef.current) startRef.current = ts;
        const progress = (ts - startRef.current) / duration;
        if (progress >= 1) {
          setPlaying(false);
          setAlpha(0.5);
          return;
        }
        const t = progress < 0.5 ? progress * 2 : 2 - progress * 2;
        setAlpha(parseFloat((0.05 + t * 3.95).toFixed(2)));
        animRef.current = requestAnimationFrame(animate);
      };
      animRef.current = requestAnimationFrame(animate);
      return () => { if (animRef.current) cancelAnimationFrame(animRef.current); };
    }
  }, [playing]);

  const W = 560, H = 290;
  const pad = { t: 25, r: 25, b: 35, l: 48 };
  const pW = W - pad.l - pad.r;
  const pH = H - pad.t - pad.b;
  const xMin = -5, xMax = 5;
  const yMin = -2.2, yMax = 2.2;

  const toX = (x) => pad.l + ((x - xMin) / (xMax - xMin)) * pW;
  const toY = (y) => pad.t + ((yMax - y) / (yMax - yMin)) * pH;
  const fromSvgX = (sx) => xMin + ((sx - pad.l) / pW) * (xMax - xMin);

  const curvePath = useMemo(() => {
    const pts = [];
    for (let i = 0; i <= 300; i++) {
      const x = xMin + (i / 300) * (xMax - xMin);
      const y = Math.max(yMin, Math.min(yMax, dyt(x, alpha, gamma, beta)));
      pts.push((i === 0 ? 'M' : 'L') + toX(x).toFixed(1) + ',' + toY(y).toFixed(1));
    }
    return pts.join('');
  }, [alpha, gamma, beta]);

  const identityPath = useMemo(() => {
    const pts = [];
    for (let i = 0; i <= 100; i++) {
      const x = xMin + (i / 100) * (xMax - xMin);
      const y = Math.max(yMin, Math.min(yMax, x));
      pts.push((i === 0 ? 'M' : 'L') + toX(x).toFixed(1) + ',' + toY(y).toFixed(1));
    }
    return pts.join('');
  }, []);

  const samples = [-3, -1.5, 0, 1.5, 3];

  const handleMouseMove = (e) => {
    const svg = svgRef.current;
    if (!svg) return;
    const rect = svg.getBoundingClientRect();
    const sx = (e.clientX - rect.left) * (W / rect.width);
    const x = fromSvgX(sx);
    if (x >= xMin && x <= xMax) {
      setHoverX(parseFloat(x.toFixed(2)));
    } else {
      setHoverX(null);
    }
  };

  const reset = () => {
    setAlpha(0.5);
    setGamma(1.0);
    setBeta(0.0);
    setHoverX(null);
    setPlaying(false);
    if (animRef.current) cancelAnimationFrame(animRef.current);
  };

  const presets = [
    { label: 'Nearly Linear', a: 0.1 },
    { label: 'Default (0.5)', a: 0.5 },
    { label: 'Aggressive', a: 2.0 },
    { label: 'Hard Clip', a: 4.0 },
  ];

  const getInsight = () => {
    if (alpha < 0.15) return 'Very low alpha: DyT is almost the identity function (gray line). Inputs pass through unchanged -- like having NO normalization at all.';
    if (alpha < 0.4) return 'Low alpha: A gentle S-curve begins to form. Extreme values are slightly compressed, but the center remains nearly linear.';
    if (alpha < 0.8) return 'Default range: DyT gently squashes extreme values toward +/-1 while keeping central values nearly linear. This mimics Layer Normalization\'s effect!';
    if (alpha < 1.5) return 'High alpha: The squashing is stronger. Values beyond +/-2 are pushed firmly toward the gamma bounds. The "normalization" effect is aggressive.';
    if (alpha < 3.0) return 'Very high alpha: DyT approaches a hard step function. Almost all non-zero inputs are clipped to +/-gamma. Too extreme for most models.';
    return 'Extreme alpha: A nearly binary function -- everything snaps to +/-gamma. This shows why the default alpha of 0.5 provides the right balance.';
  };

  const hoverY = hoverX !== null ? dyt(hoverX, alpha, gamma, beta) : null;

  const gridXs = [-4, -2, 0, 2, 4];
  const gridYs = [-2, -1, 0, 1, 2];

  return (
    <div style={{
      minHeight: '100vh',
      background: theme.colors.background,
      color: theme.colors.text,
      fontFamily: theme.font,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      padding: '16px 12px',
      boxSizing: 'border-box',
    }}>
      <div style={{ maxWidth: 600, width: '100%' }}>
        {/* Title Row */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
          <div>
            <div style={{ fontSize: 18, fontWeight: 700 }}>Dynamic Tanh (DyT)</div>
            <div style={{ fontSize: 11, color: theme.colors.textMuted, marginTop: 2 }}>Normalization-free Transformer activation</div>
          </div>
          <div style={{ display: 'flex', gap: 6 }}>
            <button onClick={() => setPlaying(!playing)} style={{
              padding: '6px 14px', background: playing ? theme.colors.surface : theme.colors.primary,
              border: 'none', borderRadius: 6, color: theme.colors.text, fontFamily: theme.font,
              fontSize: 13, cursor: 'pointer', fontWeight: 600,
            }}>{playing ? 'Pause' : 'Play'}</button>
            <button onClick={reset} style={{
              padding: '6px 10px', background: theme.colors.surface, border: 'none',
              borderRadius: 6, color: theme.colors.text, fontFamily: theme.font, fontSize: 13, cursor: 'pointer',
            }}>Reset</button>
          </div>
        </div>

        {/* Formula */}
        <div style={{
          background: theme.colors.surface, borderRadius: 8, padding: '8px 14px',
          marginBottom: 10, fontSize: 13, textAlign: 'center', display: 'flex',
          alignItems: 'center', justifyContent: 'center', gap: 4, flexWrap: 'wrap',
        }}>
          <span style={{ color: theme.colors.textMuted }}>DyT(x) =</span>
          <span style={{ color: theme.colors.yellow }}>{gamma.toFixed(1)}</span>
          <span style={{ color: theme.colors.textMuted }}>* tanh(</span>
          <span style={{ color: theme.colors.primary, fontWeight: 700 }}>{alpha.toFixed(2)}</span>
          <span style={{ color: theme.colors.textMuted }}>* x ) +</span>
          <span style={{ color: theme.colors.orange }}>{beta.toFixed(1)}</span>
        </div>

        {/* SVG Curve */}
        <div style={{
          background: theme.colors.surface, borderRadius: 10, padding: 4, marginBottom: 10,
        }}>
          <svg
            ref={svgRef}
            viewBox={'0 0 ' + W + ' ' + H}
            width="100%"
            style={{ display: 'block', cursor: 'crosshair' }}
            onMouseMove={handleMouseMove}
            onMouseLeave={() => setHoverX(null)}
          >
            {/* Grid lines */}
            {gridXs.map(gx => (
              <line key={'gx' + gx} x1={toX(gx)} y1={pad.t} x2={toX(gx)} y2={H - pad.b}
                stroke={theme.colors.border} strokeWidth={gx === 0 ? 1.5 : 0.5}
                strokeDasharray={gx === 0 ? 'none' : '3,3'} />
            ))}
            {gridYs.map(gy => (
              <line key={'gy' + gy} x1={pad.l} y1={toY(gy)} x2={W - pad.r} y2={toY(gy)}
                stroke={theme.colors.border} strokeWidth={gy === 0 ? 1.5 : 0.5}
                strokeDasharray={gy === 0 ? 'none' : '3,3'} />
            ))}

            {/* Axis labels */}
            {gridXs.map(gx => (
              <text key={'lx' + gx} x={toX(gx)} y={H - pad.b + 16}
                fill={theme.colors.textMuted} fontSize={10} textAnchor="middle">{gx}</text>
            ))}
            {gridYs.filter(g => g !== 0).map(gy => (
              <text key={'ly' + gy} x={pad.l - 10} y={toY(gy) + 4}
                fill={theme.colors.textMuted} fontSize={10} textAnchor="end">{gy}</text>
            ))}

            {/* Saturation bounds */}
            <line x1={pad.l} y1={toY(gamma + beta)} x2={W - pad.r} y2={toY(gamma + beta)}
              stroke={theme.colors.yellow} strokeWidth={0.7} strokeDasharray="6,4" opacity={0.4} />
            <line x1={pad.l} y1={toY(-gamma + beta)} x2={W - pad.r} y2={toY(-gamma + beta)}
              stroke={theme.colors.yellow} strokeWidth={0.7} strokeDasharray="6,4" opacity={0.4} />

            {/* Identity line (y=x) for reference */}
            <path d={identityPath} fill="none" stroke={theme.colors.textMuted}
              strokeWidth={1} strokeDasharray="4,4" opacity={0.35} />
            <text x={toX(1.8)} y={toY(2.05)} fill={theme.colors.textMuted} fontSize={9} opacity={0.5}>y = x (no transform)</text>

            {/* DyT curve */}
            <path d={curvePath} fill="none" stroke={theme.colors.primary}
              strokeWidth={2.5} strokeLinecap="round" />

            {/* Sample points */}
            {samples.map((sx, i) => {
              const sy = dyt(sx, alpha, gamma, beta);
              const cx = toX(sx);
              const cy = toY(Math.max(yMin, Math.min(yMax, sy)));
              return (
                <g key={'s' + i}>
                  {/* Vertical line from x-axis to curve */}
                  <line x1={cx} y1={toY(0)} x2={cx} y2={cy}
                    stroke={sampleColors[i]} strokeWidth={1} strokeDasharray="2,2" opacity={0.4} />
                  {/* Horizontal line from y-axis to curve */}
                  <line x1={pad.l} y1={cy} x2={cx} y2={cy}
                    stroke={sampleColors[i]} strokeWidth={1} strokeDasharray="2,2" opacity={0.3} />
                  {/* Point */}
                  <circle cx={cx} cy={cy} r={5}
                    fill={sampleColors[i]} stroke={theme.colors.surface} strokeWidth={1.5} />
                  {/* Label */}
                  <text x={cx} y={cy + (sy > 0 ? 16 : -8)}
                    fill={sampleColors[i]} fontSize={9} textAnchor="middle" fontWeight={600}>
                    {sy.toFixed(2)}
                  </text>
                </g>
              );
            })}

            {/* Hover crosshair */}
            {hoverX !== null && hoverY !== null && (
              <g>
                <line x1={toX(hoverX)} y1={pad.t} x2={toX(hoverX)} y2={H - pad.b}
                  stroke={theme.colors.text} strokeWidth={0.5} opacity={0.3} />
                <line x1={pad.l} y1={toY(Math.max(yMin, Math.min(yMax, hoverY)))} x2={W - pad.r}
                  y2={toY(Math.max(yMin, Math.min(yMax, hoverY)))}
                  stroke={theme.colors.text} strokeWidth={0.5} opacity={0.3} />
                <circle cx={toX(hoverX)} cy={toY(Math.max(yMin, Math.min(yMax, hoverY)))}
                  r={4} fill={theme.colors.green} stroke={theme.colors.surface} strokeWidth={1.5} />
                <rect x={toX(hoverX) + 8} y={toY(Math.max(yMin, Math.min(yMax, hoverY))) - 22}
                  width={110} height={20} rx={4} fill={theme.colors.surfaceAlt} opacity={0.92} />
                <text x={toX(hoverX) + 14} y={toY(Math.max(yMin, Math.min(yMax, hoverY))) - 8}
                  fill={theme.colors.green} fontSize={10} fontFamily={theme.font}>
                  {'x=' + hoverX.toFixed(1) + ' -> ' + hoverY.toFixed(3)}
                </text>
              </g>
            )}

            {/* Curve label */}
            <text x={toX(3.2)} y={toY(Math.max(yMin, Math.min(yMax, dyt(3.2, alpha, gamma, beta)))) - 10}
              fill={theme.colors.primary} fontSize={10} fontWeight={600}>DyT</text>
          </svg>
        </div>

        {/* Presets */}
        <div style={{ display: 'flex', gap: 6, marginBottom: 10, flexWrap: 'wrap' }}>
          {presets.map((p) => (
            <button key={p.label} onClick={() => setAlpha(p.a)} style={{
              flex: 1, padding: '6px 8px',
              background: Math.abs(alpha - p.a) < 0.05 ? theme.colors.primary + '30' : theme.colors.surfaceAlt,
              border: Math.abs(alpha - p.a) < 0.05 ? '1px solid ' + theme.colors.primary : '1px solid ' + theme.colors.border,
              borderRadius: 6, color: Math.abs(alpha - p.a) < 0.05 ? theme.colors.primary : theme.colors.textSecondary,
              fontFamily: theme.font, fontSize: 11, cursor: 'pointer', textAlign: 'center', minWidth: 0,
            }}>{p.label}</button>
          ))}
        </div>

        {/* Alpha Slider - THE MAIN THING */}
        <div style={{
          background: theme.colors.surface, borderRadius: 8, padding: '10px 14px', marginBottom: 8,
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 }}>
            <span style={{ fontSize: 13, fontWeight: 700, color: theme.colors.primary }}>alpha</span>
            <span style={{ fontSize: 16, fontWeight: 700, color: theme.colors.primary }}>{alpha.toFixed(2)}</span>
          </div>
          <input type="range" min="0.05" max="4" step="0.01" value={alpha}
            onChange={(e) => setAlpha(parseFloat(e.target.value))}
            style={{ width: '100%', accentColor: theme.colors.primary, height: 6, cursor: 'pointer' }} />
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9, color: theme.colors.textMuted, marginTop: 2 }}>
            <span>0.05 (linear)</span>
            <span>4.0 (step function)</span>
          </div>
        </div>

        {/* Gamma & Beta - secondary */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
          <div style={{
            flex: 1, background: theme.colors.surface, borderRadius: 8, padding: '8px 12px',
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
              <span style={{ fontSize: 11, color: theme.colors.yellow }}>gamma</span>
              <span style={{ fontSize: 12, fontWeight: 600, color: theme.colors.yellow }}>{gamma.toFixed(1)}</span>
            </div>
            <input type="range" min="0.2" max="2.5" step="0.1" value={gamma}
              onChange={(e) => setGamma(parseFloat(e.target.value))}
              style={{ width: '100%', accentColor: theme.colors.yellow, height: 4, cursor: 'pointer' }} />
          </div>
          <div style={{
            flex: 1, background: theme.colors.surface, borderRadius: 8, padding: '8px 12px',
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
              <span style={{ fontSize: 11, color: theme.colors.orange }}>beta</span>
              <span style={{ fontSize: 12, fontWeight: 600, color: theme.colors.orange }}>{beta.toFixed(1)}</span>
            </div>
            <input type="range" min="-1" max="1" step="0.1" value={beta}
              onChange={(e) => setBeta(parseFloat(e.target.value))}
              style={{ width: '100%', accentColor: theme.colors.orange, height: 4, cursor: 'pointer' }} />
          </div>
        </div>

        {/* Sample values table */}
        <div style={{
          background: theme.colors.surface, borderRadius: 8, padding: '8px 12px', marginBottom: 10,
          display: 'flex', justifyContent: 'space-around', alignItems: 'center',
        }}>
          {samples.map((sx, i) => {
            const sy = dyt(sx, alpha, gamma, beta);
            return (
              <div key={i} style={{ textAlign: 'center' }}>
                <div style={{ fontSize: 10, color: theme.colors.textMuted }}>x={sx}</div>
                <div style={{ fontSize: 9, color: theme.colors.textMuted, margin: '1px 0' }}>-></div>
                <div style={{
                  fontSize: 12, fontWeight: 700, color: sampleColors[i],
                  transition: 'all 0.15s ease',
                }}>{sy.toFixed(3)}</div>
              </div>
            );
          })}
        </div>

        {/* Key Insight */}
        <div style={{
          background: theme.colors.surfaceAlt, borderRadius: 8, padding: '10px 14px',
          fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.6,
          borderLeft: '3px solid ' + theme.colors.primary, transition: 'all 0.3s ease',
        }}>
          <span style={{ color: theme.colors.primary, fontWeight: 600 }}>Insight: </span>
          {getInsight()}
        </div>
      </div>
    </div>
  );
}
